export interface WordProgress {
  known: boolean;
  attempts: number;
  correct: number;
  lastSeen: number;
}

export interface UserProgress {
  words: Record<string, WordProgress>;
  studyStreak: number;
  lastStudyDate: string;
}

export function loadProgress(): UserProgress {
  try {
    const raw = localStorage.getItem("danish-vocab-progress");
    if (raw) return JSON.parse(raw);
  } catch {}
  return { words: {}, studyStreak: 0, lastStudyDate: "" };
}

export function saveProgress(p: UserProgress): void {
  localStorage.setItem("danish-vocab-progress", JSON.stringify(p));
}

export function markWord(p: UserProgress, id: string, known: boolean): UserProgress {
  const prev = p.words[id] || { known: false, attempts: 0, correct: 0, lastSeen: 0 };
  const today = new Date().toISOString().split("T")[0];
  const streak = p.lastStudyDate === today ? p.studyStreak :
    p.lastStudyDate === new Date(Date.now() - 86400000).toISOString().split("T")[0]
      ? p.studyStreak + 1 : 1;
  return {
    ...p,
    studyStreak: streak,
    lastStudyDate: today,
    words: {
      ...p.words,
      [id]: { known, attempts: prev.attempts + 1, correct: prev.correct + (known ? 1 : 0), lastSeen: Date.now() },
    },
  };
}

